import React, { useState } from "react";
import "./Contact.css";

export default function Contact({ navigate }) {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    msg: "",
  });
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const formData = new FormData();
      formData.append("name", form.name);
      formData.append("email", form.email);
      formData.append("phone", form.phone || "Not provided");
      formData.append("subject", form.subject || "No Subject");
      formData.append("message", form.msg);

      // FormSubmit configs
      formData.append(
        "_subject",
        `New Contact Form Submission from ${form.name}`
      );
      formData.append("_template", "table");
      formData.append("_captcha", "false");

      const response = await fetch(
        "https://formsubmit.co/ajax/27a84a5d10c8b72fb274e40b7f45b117",
        {
          method: "POST",
          body: formData,
        }
      );

      const result = await response.json();

      if (result.success === "true") {
        setSent(true);
        setForm({
          name: "",
          email: "",
          phone: "",
          subject: "",
          msg: "",
        });
      } else {
        alert("Message send nahi hua. Please try again.");
      }
    } catch (error) {
      console.error(error);
      alert("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fdct-page">
      <div className="fdct-hero">
        <span>Get In Touch</span>
        <h1>
          Contact <span>Us</span>
        </h1>
        <p>Have a question? Need a quote? Our team is ready to help 24×7.</p>
      </div>

      <section className="fdct-content fd-section">
        <div className="fd-container fdct-grid">
          {/* LEFT INFO */}
          <div className="fdct-info">
            <h2>Let's Talk</h2>
            <p>
              Whether you're a small business owner or managing a large fleet,
              our team will find the right solution for you.
            </p>

            <div className="fdct-contact-items">
              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-phone"></i>
                </div>
                <div>
                  <strong>Call Us</strong>
                  <span>+91-8088994444</span>
                  <span>Mon–Sat 8AM – 8PM</span>
                </div>
              </div>

              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-envelope"></i>
                </div>
                <div>
                  <strong>Email Us</strong>
                  <span>support@fueldrop.in</span>
                  <span>Response within 2 hours</span>
                </div>
              </div>

              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-map-marker-alt"></i>
                </div>
                <div>
                  <strong>Head Office</strong>
                  <span>Tower B, Quattro Towers</span>
                  <span>Udyog Vihar Phase 4, Gurugram 122016</span>
                </div>
              </div>
            </div>
          </div>

          {/* RIGHT FORM */}
          <div className="fdct-form-wrap">
            {sent ? (
              <div className="fdct-success">
                <div className="fdct-success-icon">✅</div>
                <h3>Message Sent!</h3>
                <p>
                  Thank you for reaching out. Our team will contact you shortly.
                </p>
                <button onClick={() => setSent(false)}>
                  Send Another Message
                </button>
              </div>
            ) : (
              <form className="fdct-form" onSubmit={handleSubmit}>
                <h3>Send a Message</h3>

                <div className="fdct-row">
                  <div className="fdct-field">
                    <label>Full Name *</label>
                    <input
                      type="text"
                      required
                      value={form.name}
                      onChange={(e) =>
                        setForm({ ...form, name: e.target.value })
                      }
                      disabled={loading}
                    />
                  </div>

                  <div className="fdct-field">
                    <label>Email *</label>
                    <input
                      type="email"
                      required
                      value={form.email}
                      onChange={(e) =>
                        setForm({ ...form, email: e.target.value })
                      }
                      disabled={loading}
                    />
                  </div>
                </div>

                <div className="fdct-row">
                  <div className="fdct-field">
                    <label>Phone</label>
                    <input
                      type="tel"
                      value={form.phone}
                      onChange={(e) =>
                        setForm({ ...form, phone: e.target.value })
                      }
                      disabled={loading}
                    />
                  </div>

                  <div className="fdct-field">
                    <label>Subject</label>
                    <input
                      type="text"
                      value={form.subject}
                      onChange={(e) =>
                        setForm({ ...form, subject: e.target.value })
                      }
                      disabled={loading}
                    />
                  </div>
                </div>

                <div className="fdct-field">
                  <label>Message *</label>
                  <textarea
                    rows="5"
                    required
                    value={form.msg}
                    onChange={(e) =>
                      setForm({ ...form, msg: e.target.value })
                    }
                    disabled={loading}
                  />
                </div>

                <button
                  type="submit"
                  className="fdct-submit"
                  disabled={loading}
                >
                  {loading ? "Sending..." : "Send Message"}{" "}
                  {!loading && <i className="fa fa-arrow-right"></i>}
                </button>
              </form>
            )}
          </div>
        </div>
      </section>
    </div>
  );
}
